#include <bits/stdc++.h>
using namespace std;
const int N=1e5+5;
int n,c,m,t[4*N],tag[4*N];
void build(int cur,int l,int r){
    if(l==r){
        t[cur]=1;
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur]=t[cur*2]|t[cur*2+1];
}
void modify(int cur,int l,int r,int x,int y,int k){
    if(x<=l && r<=y){
        t[cur]=1<<k-1,tag[cur]=k;
        return;
    }
    if(tag[cur]){
        t[cur*2]=1<<tag[cur]-1,tag[cur*2]=tag[cur];
        t[cur*2+1]=1<<tag[cur]-1,tag[cur*2+1]=tag[cur];
        tag[cur]=0;
    }
    int mid=l+r>>1;
    if(x<=mid)
        modify(cur*2,l,mid,x,y,k);
    if(y>mid)
        modify(cur*2+1,mid+1,r,x,y,k);
    t[cur]=t[cur*2]|t[cur*2+1];
}
int query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    if(tag[cur]){
        t[cur*2]=1<<tag[cur]-1,tag[cur*2]=tag[cur];
        t[cur*2+1]=1<<tag[cur]-1,tag[cur*2+1]=tag[cur];
        tag[cur]=0;
    }
    int mid=l+r>>1,ans=0;
    if(x<=mid)
        ans|=query(cur*2,l,mid,x,y);
    if(y>mid)
        ans|=query(cur*2+1,mid+1,r,x,y);
    return ans;
}
int lowbit(int x){
    return x&(-x);
}
int Sum(int x){
    int sum=0;
    while(x)
        sum++,x-=lowbit(x);
    return sum;
}
int main(){
    scanf("%d%d%d",&n,&c,&m);
    build(1,1,n);
    while(m--){
        char tp;
        cin>>tp;
        if(tp=='C'){
            int a,b,c;
            scanf("%d%d%d",&a,&b,&c);
            if(a>b)
                swap(a,b);
            modify(1,1,n,a,b,c);
        }else{
            int a,b;
            scanf("%d%d",&a,&b);
            if(a>b)
                swap(a,b);
            printf("%d\n",Sum(query(1,1,n,a,b)));
        }
    }
    return 0;
}
